    29→// Histogram is our internal representation for our wrapping struct around prometheus
    30→// histograms. Summary implements both kubeCollector and ObserverMetric
    31→type Histogram struct {
    32→	ObserverMetric
    33→	*HistogramOpts
    34→	lazyMetric
    35→	selfCollector
    36→}
