    38→// exemplarHistogramMetric holds a context to extract exemplar labels from, and a historgram metric to attach them to. It implements the metricWithExemplar interface.
    39→type exemplarHistogramMetric struct {
    40→	ctx      context.Context
    41→	delegate ObserverMetric
    42→}
    43→
    44→type exemplarHistogramVec struct {
    45→	*HistogramVecWithContext
    46→	observer prometheus.Observer
    47→}
    48→
    49→// Observe attaches an exemplar to the metric and then calls the delegate.
    50→func (e *exemplarHistogramMetric) Observe(v float64) {
    51→	if m, ok := e.delegate.(prometheus.ExemplarObserver); ok {
    52→		maybeSpanCtx := trace.SpanContextFromContext(e.ctx)
    53→		if maybeSpanCtx.IsValid() && maybeSpanCtx.IsSampled() {
    54→			exemplarLabels := prometheus.Labels{
    55→				"trace_id": maybeSpanCtx.TraceID().String(),
    56→				"span_id":  maybeSpanCtx.SpanID().String(),
    57→			}
    58→			m.ObserveWithExemplar(v, exemplarLabels)
    59→			return
    60→		}
    61→	}
    62→
    63→	e.delegate.Observe(v)
    64→}
