    66→// NewHistogram returns an object which is Histogram-like. However, nothing
    67→// will be measured until the histogram is registered somewhere.
    68→func NewHistogram(opts *HistogramOpts) *Histogram {
    69→	opts.StabilityLevel.setDefaults()
    70→
    71→	h := &Histogram{
    72→		HistogramOpts: opts,
    73→		lazyMetric:    lazyMetric{stabilityLevel: opts.StabilityLevel},
    74→	}
    75→	h.setPrometheusHistogram(noopMetric{})
    76→	h.lazyInit(h, BuildFQName(opts.Namespace, opts.Subsystem, opts.Name))
    77→	return h
    78→}
    79→
    80→// setPrometheusHistogram sets the underlying KubeGauge object, i.e. the thing that does the measurement.
    81→func (h *Histogram) setPrometheusHistogram(histogram prometheus.Histogram) {
    82→	h.ObserverMetric = histogram
    83→	h.initSelfCollection(histogram)
    84→}
    85→
    86→// DeprecatedVersion returns a pointer to the Version or nil
    87→func (h *Histogram) DeprecatedVersion() *semver.Version {
    88→	return parseSemver(h.HistogramOpts.DeprecatedVersion)
    89→}
    90→
    91→// initializeMetric invokes the actual prometheus.Histogram object instantiation
    92→// and stores a reference to it
    93→func (h *Histogram) initializeMetric() {
    94→	h.HistogramOpts.annotateStabilityLevel()
    95→	// this actually creates the underlying prometheus gauge.
    96→	h.setPrometheusHistogram(prometheus.NewHistogram(h.HistogramOpts.toPromHistogramOpts()))
    97→}
    98→
    99→// initializeDeprecatedMetric invokes the actual prometheus.Histogram object instantiation
   100→// but modifies the Help description prior to object instantiation.
   101→func (h *Histogram) initializeDeprecatedMetric() {
   102→	h.HistogramOpts.markDeprecated()
   103→	h.initializeMetric()
   104→}
   105→
   106→// WithContext allows the normal Histogram metric to pass in context. The context is no-op now.
   107→func (h *Histogram) WithContext(ctx context.Context) ObserverMetric {
   108→	return &exemplarHistogramMetric{ctx: ctx, delegate: h.ObserverMetric}
   109→}
