   111→// HistogramVec is the internal representation of our wrapping struct around prometheus
   112→// histogramVecs.
   113→type HistogramVec struct {
   114→	*prometheus.HistogramVec
   115→	*HistogramOpts
   116→	lazyMetric
   117→	originalLabels []string
   118→}
   119→
   120→// NewHistogramVec returns an object which satisfies kubeCollector and wraps the
   121→// prometheus.HistogramVec object. However, the object returned will not measure
   122→// anything unless the collector is first registered, since the metric is lazily instantiated,
   123→// and only members extracted after
   124→// registration will actually measure anything.
   125→
   126→func NewHistogramVec(opts *HistogramOpts, labels []string) *HistogramVec {
   127→	opts.StabilityLevel.setDefaults()
   128→
   129→	fqName := BuildFQName(opts.Namespace, opts.Subsystem, opts.Name)
   130→
   131→	v := &HistogramVec{
   132→		HistogramVec:   noopHistogramVec,
   133→		HistogramOpts:  opts,
   134→		originalLabels: labels,
   135→		lazyMetric:     lazyMetric{stabilityLevel: opts.StabilityLevel},
   136→	}
   137→	v.lazyInit(v, fqName)
   138→	return v
   139→}
   140→
   141→// DeprecatedVersion returns a pointer to the Version or nil
   142→func (v *HistogramVec) DeprecatedVersion() *semver.Version {
   143→	return parseSemver(v.HistogramOpts.DeprecatedVersion)
   144→}
   145→
   146→func (v *HistogramVec) initializeMetric() {
   147→	v.HistogramOpts.annotateStabilityLevel()
   148→	v.HistogramVec = prometheus.NewHistogramVec(v.HistogramOpts.toPromHistogramOpts(), v.originalLabels)
   149→}
   150→
   151→func (v *HistogramVec) initializeDeprecatedMetric() {
   152→	v.HistogramOpts.markDeprecated()
   153→	v.initializeMetric()
   154→}
