   156→// Default Prometheus Vec behavior is that member extraction results in creation of a new element
   157→// if one with the unique label values is not found in the underlying stored metricMap.
   158→// This means  that if this function is called but the underlying metric is not registered
   159→// (which means it will never be exposed externally nor consumed), the metric will exist in memory
   160→// for perpetuity (i.e. throughout application lifecycle).
   161→//
   162→// For reference: https://github.com/prometheus/client_golang/blob/v0.9.2/prometheus/histogram.go#L460-L470
   163→//
   164→// In contrast, the Vec behavior in this package is that member extraction before registration
   165→// returns a permanent noop object.
   166→
   167→// WithLabelValues returns the ObserverMetric for the given slice of label
   168→// values (same order as the VariableLabels in Desc). If that combination of
   169→// label values is accessed for the first time, a new ObserverMetric is created IFF the HistogramVec
   170→// has been registered to a metrics registry.
   171→func (v *HistogramVec) WithLabelValues(lvs ...string) ObserverMetric {
   172→	if !v.IsCreated() {
   173→		return noop
   174→	}
   175→
   176→	// Initialize label allow lists if not already initialized
   177→	v.initializeLabelAllowListsOnce.Do(func() {
   178→		allowListLock.RLock()
   179→		if allowList, ok := labelValueAllowLists[v.FQName()]; ok {
   180→			v.LabelValueAllowLists = allowList
   181→		}
   182→		allowListLock.RUnlock()
   183→	})
   184→
   185→	// Constrain label values to allowed values
   186→	if v.LabelValueAllowLists != nil {
   187→		v.LabelValueAllowLists.ConstrainToAllowedList(v.originalLabels, lvs)
   188→	}
   189→	return v.HistogramVec.WithLabelValues(lvs...)
   190→}
   191→
   192→// With returns the ObserverMetric for the given Labels map (the label names
   193→// must match those of the VariableLabels in Desc). If that label map is
   194→// accessed for the first time, a new ObserverMetric is created IFF the HistogramVec has
   195→// been registered to a metrics registry.
   196→func (v *HistogramVec) With(labels map[string]string) ObserverMetric {
   197→	if !v.IsCreated() {
   198→		return noop
   199→	}
   200→
   201→	// Initialize label allow lists if not already initialized
   202→	v.initializeLabelAllowListsOnce.Do(func() {
   203→		allowListLock.RLock()
   204→		if allowList, ok := labelValueAllowLists[v.FQName()]; ok {
   205→			v.LabelValueAllowLists = allowList
   206→		}
   207→		allowListLock.RUnlock()
   208→	})
   209→
   210→	// Constrain label map to allowed values
   211→	if v.LabelValueAllowLists != nil {
   212→		v.LabelValueAllowLists.ConstrainLabelMap(labels)
   213→	}
   214→
   215→	return v.HistogramVec.With(labels)
   216→}
   217→
   218→// ObserveSince returns a function that observes the duration since the given start time.
   219→// This is intended to be used with defer to measure the time elapsed since a given point:
   220→//
   221→//	start := time.Now()
   222→//	defer metricVec.ObserveSince(start, "label1", "label2")()
   223→//
   224→// The returned function must be called (typically via defer) to record the observation.
   225→// This pattern avoids the common pitfall where arguments to deferred functions are evaluated
   226→// immediately, which would result in incorrect timing measurements.
   227→func (v *HistogramVec) ObserveSince(start time.Time, lvs ...string) func() {
   228→	return func() {
   229→		v.WithLabelValues(lvs...).Observe(time.Since(start).Seconds())
   230→	}
   231→}
