   233→// Delete deletes the metric where the variable labels are the same as those
   234→// passed in as labels. It returns true if a metric was deleted.
   235→//
   236→// It is not an error if the number and names of the Labels are inconsistent
   237→// with those of the VariableLabels in Desc. However, such inconsistent Labels
   238→// can never match an actual metric, so the method will always return false in
   239→// that case.
   240→func (v *HistogramVec) Delete(labels map[string]string) bool {
   241→	if !v.IsCreated() {
   242→		return false // since we haven't created the metric, we haven't deleted a metric with the passed in values
   243→	}
   244→	return v.HistogramVec.Delete(labels)
   245→}
